let select = (e) => document.querySelector(e);
let selectAll = (e) => document.querySelectorAll(e);

const select01 = select("#select01"),
options = select01.querySelectorAll("option"),
icons = select("#icons");

var bgId = 521;

/* does browser have CSS appearance: base-select support? */
let appearanceBaseSelectEnabled = false;
if ( window.getComputedStyle(select01).getPropertyValue("appearance") == "base-select" )
	appearanceBaseSelectEnabled = true;

/* update background image on select change */
select01.addEventListener("change", function() {

    const tl2 = gsap.timeline()
    .set( "#bg" + bgId, { className: "bgImg sub" } )
    .set( "#bg" + this.value, { className: "bgImg active" } )
    .to( "#bg" + this.value, { opacity: 0.9, duration: 1, } )
    .to( "#bg" + bgId, { opacity: 0, duration: 0.25, }, 0.75 )
    .set( "#bg" + bgId, { className: "bgImg" } );

    bgId = this.value;

});

$( document ).ready(function() {


    /* setup GSAP interactive animation if browser isn't supported */  
    if( !appearanceBaseSelectEnabled )
    {

        icons.addEventListener("mouseover", function() { tl1.play(); }, false);
        icons.addEventListener("mouseout", function() { tl1.reverse(); }, false);
        icons.addEventListener('touchstart', function(event) { tl1.play(); }, false);
        icons.addEventListener('touchend', function(event) { tl1.reverse(); }, false);

        const tl1 = gsap
        .timeline({ paused: true, defaults: { duration: 0.4, ease: "none" } })
        .fromTo( "#mouth", { morphSVG: "#mouth1b" }, { morphSVG: "#mouth2b", duration: 0.2 } )
        .fromTo( "#mouth", { morphSVG: "#mouth2b" }, { morphSVG: "#mouth3b", duration: 0.2 }, 0.2 )
        .fromTo( "#head", { morphSVG: "#head1b" }, { morphSVG: "#head2b" }, 0 )
        .fromTo( "#lEye", { morphSVG: "#lEye1b" }, { morphSVG: "#lEye2b" }, 0 )
        .fromTo( "#rEye", { morphSVG: "#rEye1b" }, { morphSVG: "#rEye2b" }, 0 );
        gsap.set( "#mouth", { morphSVG: "#mouth1b" });
        gsap.set( "#head", { morphSVG: "#head1b" });

    }

    /* load all secondary background images */
    gsap.set("#bg524", { css:{backgroundImage: "url(https://picsum.photos/id/524/1500)" } } );
    gsap.set("#bg444", { css:{backgroundImage: "url(https://picsum.photos/id/444/1500)" } } );
    gsap.set("#bg299", { css:{backgroundImage: "url(https://picsum.photos/id/299/1500)" } } );
    gsap.set("#bg1075", { css:{backgroundImage: "url(https://picsum.photos/id/1075/1500)" } } );
    gsap.set("#bg893", { css:{backgroundImage: "url(https://picsum.photos/id/893/1500)" } } );
    gsap.set("#bg549", { css:{backgroundImage: "url(https://picsum.photos/id/549/1500)" } } );

});

style.css:
@import url('https://fonts.googleapis.com/css2?family=Roboto:ital,wght@0,100..900;1,100..900&display=swap');
@import url("https://cdn.jsdelivr.net/npm/bootstrap-icons@1.13.1/font/bootstrap-icons.min.css");

*, *::before, *::after {
    box-sizing: border-box!important;
}

html, body {
    font-family: Avenir, sans-serif;
    width: 100%;
    height: 100%;
    margin: 0;
    padding: 0px;
}

body {
    background: #000000;
    font-optical-sizing: auto;
    font-weight: 400;
    font-style: normal;
    font-variation-settings: "wdth" 100;
    color: #FFFFFF;
    overflow: hidden;
}


#gsapBody {

    display: block;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    height: 100vh;

    select {
        display: block;
        position: relative;
        z-index: 100;
        width: 460px;
        margin: auto;
        padding: 0px;
        padding-top: 15px;
        padding-bottom: 15px;
        border-radius: 30px;
        background: linear-gradient(0deg, #FFF9 0px, #FFF3 10px, #FFF0, #FFF0, #FFF3 calc( 100% - 10px ), #FFF9 100%), #9991;
        /* backdrop-filter: url(#glass) blur(6px); */
        border: solid 2px #FFF9;
        box-shadow: 2px 2px 4px 0 #0006, -1px -1px 1px 0 #0002;
        color: #FFF;
        font-size: 20px;
        text-shadow: 0px 0px 6px #000;
        white-space: nowrap;
        cursor: pointer;
        outline: none;

        &:hover {
            background: linear-gradient(0deg, #FFF9 0px, #FFF3 10px, #FFF0, #FFF0, #FFF3 calc( 100% - 10px ), #FFF9 100%), #FFF4;
            color: #FFF;
            cursor: pointer;
        }

    }

    @supports not (appearance: base-select) {

        .selectWrapper {

            position: relative;

            &::after {
                display: inline-block;
                position: absolute;
                right: 25px;
                top: 17px;
                z-index: 110;
                content: url('');
                width: 24px;
                height: 24px;
                background-image: url('data:image/svg+xml,<svg width="24" height="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" xmlns:svg="http://www.w3.org/2000/svg"><path fill="%23FFFFFF" stroke="none" d="M 5,7 12,18 19,7 Z" /></svg>');
                background-repeat: no-repeat;
            }

            select {

                -moz-appearance: none;
                -webkit-appearance: none;
                &::-ms-expand { display: none; }

            }

        }

    }  

    @supports (appearance: base-select) {

        .selectWrapper {

            position: relative;

            select {

                &, &::picker(select) { appearance: base-select; }

                &::picker-icon { margin-right: 25px; }

                /* backdrop-filter: url(#glass) blur(6px); */
                backdrop-filter: url(#glass);

                height: 75vh;
                max-height: 60px;
                transition: max-height 0.25s ease-out;
                transform-origin: center center;
                text-indent: 25px;
                overflow-y: clip;

                &:open {

                    background: linear-gradient(0deg, #FFF 0px, #FFF3 25px, #FFF0, #FFF0, #FFF3 calc( 100% - 25px ), #FFF 100%), #FFF4;
                    color: #FFF0;
                    max-height: 75vh;
                    padding-top: 0px;
                    padding-bottom: 0px;
                    transition: max-height 0.25s ease-out, color 0.25s ease-out;
                    text-shadow: none!important;

                    &::picker-icon { display: none; }

                    .optGWrapper {

                       display: block;
                        height: 75vh;
                        padding-top: 12px;
                        padding-bottom: 12px;
                        padding-right: 10px;
                        overflow: clip;

                        .optG {
                           display: block;
                            margin: auto;
                            opacity: 1;
                            height: calc( 75vh - 24px );
                            max-height: calc( 75vh - 24px );
                            overflow-y: auto;

                            option {

                                position: relative;
                                opacity: 1;
                                height: 120px;
                                max-height: 120px;

                                margin: 10px;
                                padding: 0px;
                                padding-right: 25px;
                                border-radius: 18px;
                                border: solid 1px #0002;
                                background-color: #0001;
                                color: #FFFFFF;
                                text-shadow: 0px 0px 4px #0008;
                                box-shadow: 0px 0px 1px #0004;
                                cursor: pointer;
                                text-indent: 0px;
                                line-height: 30px;
                                overflow-y: clip;
                                outline: none;

                                &:first-of-type { margin-top: 3px; }
                                &:last-of-type { margin-bottom: 3px; }

                                &:hover, &:focus {
                                    border: solid 1px #0004;
                                    background-color: #0003;
                                    color: #FFFFFF!important;
                                }
                                &:after{
                                    position: absolute;
                                    left: 145px;
                                    top: 250px;
                                    right: 10px;
                                    font-size: 16px;
                                    line-height: normal;
                                    white-space: normal;
                                    font-weight: 200;
                                    transition: all 0.5s ease-in-out;
                                    opacity: 0;
                                    content: attr(data-desc);
                                }
                                &:hover {
                                    &:after {
                                        top: 75px;
                                        opacity: 1;
                                    }
                                }

                                .option-label { height: auto!important; }

                                .icon {
                                    display: block;
                                    float: left;
                                    width: 120px;
                                    height: 120px;
                                    margin-right: 15px;
                                    border-top-left-radius: 18px;
                                    border-bottom-left-radius: 18px;
                                    background-color: #0001;  
                                    background-position: center center;
                                    background-size: cover;
                                    background-repeat: no-repeat;
                                    filter: brightness(75%);
                                    transition: all 0.5s ease;
                                }
                                &:hover, &:focus {
                                    .icon {
                                        filter: brightness(100%);
                                    }
                                }

                            }

                            ::checkmark {
                                position: absolute;
                                left: 85px;
                                bottom: 0px;
                                z-index: 10;
                                font-family: "Titan One", sans-serif;
                                font-size: 60px;
                                font-weight: 900;
                                line-height: normal;
                                content: "✓";
                            }

                        }

                    }

                    &::picker {
                        position: relative;
                        z-index: -1;
                    }

                    &::picker(select) {

                        background: transparent!important;
                        opacity: 0;
                        height: 75vh;
                        overflow: clip;
                        border: none!important;

                    }

                    &:open, &:open * {

                        opacity: 1;
                        transition-delay: 2s;
                        transition: max-height 0.15s ease-in, opacity 1.5s ease-in;

                        @starting-style {
                            max-height: 0px;
                            opacity: 0;
                        }

                    }
                    &:open::picker(select) {

                        max-height: 75vh;
                        height: 75vh;
                        transform: translateY( -75vh );
                        transition: all 0.5s ease-in;
                        opacity: 1;

                        .option-label {
                            height: auto!important;
                        }        

                    }



                    .foregroundBlur {
                        display: block!important;
                        content: " ";
                        position: absolute;
                        left: 2px;
                        right: 2px;
                        z-index: 5;
                        opacity: 1;
                        height: 30px;
                        max-height: 30px;
                        &#fTop {
                            top: 2px;
                            border-top-left-radius: 30px;
                            border-top-right-radius: 30px;
                            mask: linear-gradient( black, black, transparent );
                            backdrop-filter: blur(8px);
                        }
                        &#fBottom {
                            bottom: 2px;
                            border-bottom-left-radius: 30px;
                            border-bottom-right-radius: 30px;
                            mask: linear-gradient( transparent, black, black );
                            backdrop-filter: blur(8px);
                        }
                    }

                }

            }

        }

        #browserSupport { display: none; }

    }


    @supports not (appearance: base-select) {

        select {


            backdrop-filter: blur(6px);
            height: 60px;
            text-indent: 15px;
            cursor: pointer;

            option, ::selection {
                color: #000000;
                text-shadow: none;
                cursor: pointer;
            }

        }

        #browserSupport {

            display: flex;
            flex-direction: column;
            justify-content: center;

            position: relative;
            z-index: 1;
            width: 450px;
            min-height: 200px;
            margin-top: 25px;
            padding-left: 150px;
            text-shadow: 0px 0px 6px #0009;

            svg#face {
                position: absolute;
                left: 10px;
                top: 0px;
                width: 125px;
                height: 125px;
                fill: #FFFFFF;
                color: #FFFFFF;
            }

            h1, h2, h3 { margin: 0px; padding: 0px; padding-bottom: 10px; }

            h1 {
                font-family: "Titan One", sans-serif;
                font-size: 36px;
                font-weight: 900;

            }
            h2 { font-size: 18px; }
            h3 { font-size: 16px; }

            #icons {

                display: inline-block;
                width: 106px;
                margin-top: 15px;
                cursor: pointer;
                padding: 2px;
                border-radius: 100px;
                background-color: #ceead6;
                box-shadow: 0 0 1em 0 #0006;
                text-decoration: none;
                overflow: hidden;

                img {

                    float: left;
                    width: 30px;
                    height: 30px;
                    margin: 2px;

                }
            }

        }

    }

}


.scroll {

    overflow-y: scroll;

    &::-webkit-scrollbar {
        width: 5px;
        background-color: transparent;
    }
    &::-webkit-scrollbar-track {
        background-color: transparent;
        padding-right: 5px;
    }
    &::-webkit-scrollbar-thumb {
        width: 5px;
        background: linear-gradient( #0000, #0000 20px, #0002 20px, #0002 calc( 100% - 20px ), #0000 calc( 100% - 20px ), #0000 100% );
        border: none;
    }

}


.bgImg {
    display: block;
    position: fixed;
    left: 0px;
    top: 0px;
    z-index: -1;
    width: 100vw;
    height: 100vh;
    background-position: center center;
    background-size: cover;
    background-repeat: no-repeat;
    opacity: 0;
    z-index: -2;

    &.active { z-index: 0; }
    &.sub { z-index: -1; }

}
